"use client";

import { useState, useRef, useCallback, useEffect } from 'react';

interface StreamingTranscriptionState {
  isRecording: boolean;
  isVADActive: boolean;
  interimText: string;
  finalText: string;
  audioLevel: number;
  predictedPunctuation: string;
  bufferSize: number;
  isConnected: boolean;
}

interface UseStreamingTranscriptionReturn extends StreamingTranscriptionState {
  startRecording: () => Promise<void>;
  stopRecording: () => void;
  toggleRecording: () => Promise<void>;
}

// Audio processing constants
const SAMPLE_RATE = 16000; // 16kHz for voice
const BUFFER_SIZE = 4096;
const VAD_THRESHOLD = 0.015; // Energy threshold for voice detection
const VAD_SILENCE_TIMEOUT = 800; // ms - commit after this much silence
const STREAMING_INTERVAL = 500; // ms - send buffer every 500ms
const OVERLAP_DURATION = 200; // ms - overlap between buffers

// Interrogatives for quick question detection
const INTERROGATIVES = [
  'who', 'what', 'where', 'why', 'how', 'when', 'which', 
  'is', 'are', 'can', 'could', 'would', 'should', 'will',
  'do', 'does', 'did', 'have', 'has', 'am'
];

export function useStreamingTranscription(
  onTranscript: (text: string, isFinal: boolean) => void,
  wsUrl: string = 'wss://api.koda-ai.com/stream'
): UseStreamingTranscriptionReturn {
  const [state, setState] = useState<StreamingTranscriptionState>({
    isRecording: false,
    isVADActive: false,
    interimText: '',
    finalText: '',
    audioLevel: 0,
    predictedPunctuation: '',
    bufferSize: 0,
    isConnected: false,
  });

  // Refs for audio processing
  const audioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const sourceNodeRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorNodeRef = useRef<ScriptProcessorNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  
  // Buffer management
  const audioBufferRef = useRef<Float32Array[]>([]);
  const overlapBufferRef = useRef<Float32Array | null>(null);
  const vadBufferRef = useRef<number[]>([]);
  const silenceStartRef = useRef<number | null>(null);
  const streamingIntervalRef = useRef<NodeJS.Timeout | null>(null);
  
  // WebSocket
  const wsRef = useRef<WebSocket | null>(null);
  const reconnectAttemptsRef = useRef(0);
  const maxReconnectAttempts = 5;

  // VAD: Calculate RMS energy
  const calculateEnergy = useCallback((buffer: Float32Array): number => {
    let sum = 0;
    for (let i = 0; i < buffer.length; i++) {
      sum += buffer[i] * buffer[i];
    }
    return Math.sqrt(sum / buffer.length);
  }, []);

  // VAD: Check if speech is detected
  const isSpeechDetected = useCallback((energy: number): boolean => {
    // Maintain a moving average for adaptive threshold
    vadBufferRef.current.push(energy);
    if (vadBufferRef.current.length > 50) {
      vadBufferRef.current.shift();
    }
    
    const avgEnergy = vadBufferRef.current.reduce((a, b) => a + b, 0) / vadBufferRef.current.length;
    const threshold = Math.max(VAD_THRESHOLD, avgEnergy * 1.5);
    
    return energy > threshold;
  }, []);

  // Quick question detection with regex/heuristics
  const detectQuestion = useCallback((text: string): string => {
    const trimmed = text.trim();
    if (!trimmed) return '';
    
    const words = trimmed.split(/\s+/);
    const firstWord = words[0]?.toLowerCase();
    const lastWord = words[words.length - 1]?.toLowerCase();
    
    // Check for interrogative starters
    if (INTERROGATIVES.includes(firstWord)) {
      // Check for rising intonation indicators (last word)
      const risingIndicators = ['right', 'yes', 'no', 'ok', 'okay', 'please', 'thanks', 'huh'];
      const isRising = risingIndicators.includes(lastWord);
      
      // If rising or it's a short question, predict ?
      if (isRising || words.length < 6) {
        return '?';
      }
    }
    
    // Check for statement patterns (longer, no interrogative)
    if (words.length > 8 && !INTERROGATIVES.includes(firstWord)) {
      return '.';
    }
    
    return '';
  }, []);

  // Downsample audio to 16kHz
  const downsampleAudio = useCallback((
    buffer: Float32Array, 
    inputSampleRate: number
  ): Float32Array => {
    if (inputSampleRate === SAMPLE_RATE) return buffer;
    
    const ratio = inputSampleRate / SAMPLE_RATE;
    const newLength = Math.round(buffer.length / ratio);
    const result = new Float32Array(newLength);
    
    for (let i = 0; i < newLength; i++) {
      const idx = Math.round(i * ratio);
      result[i] = buffer[idx] || 0;
    }
    
    return result;
  }, []);

  // Convert Float32 to Int16 for efficient transmission
  const floatToInt16 = useCallback((buffer: Float32Array): Int16Array => {
    const int16Buffer = new Int16Array(buffer.length);
    for (let i = 0; i < buffer.length; i++) {
      const s = Math.max(-1, Math.min(1, buffer[i]));
      int16Buffer[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    return int16Buffer;
  }, []);

  // Send audio buffer via WebSocket
  const sendAudioBuffer = useCallback(() => {
    if (!wsRef.current || wsRef.current.readyState !== WebSocket.OPEN) return;
    if (audioBufferRef.current.length === 0) return;

    // Create overlapping buffer
    const buffers = audioBufferRef.current;
    let combinedLength = 0;
    buffers.forEach(b => combinedLength += b.length);
    
    // Add overlap from previous buffer
    if (overlapBufferRef.current) {
      combinedLength += overlapBufferRef.current.length;
    }
    
    const combined = new Float32Array(combinedLength);
    let offset = 0;
    
    // Add overlap first
    if (overlapBufferRef.current) {
      combined.set(overlapBufferRef.current, offset);
      offset += overlapBufferRef.current.length;
    }
    
    // Add current buffers
    buffers.forEach(buffer => {
      combined.set(buffer, offset);
      offset += buffer.length;
    });
    
    // Store overlap for next buffer
    const overlapSamples = Math.floor(SAMPLE_RATE * OVERLAP_DURATION / 1000);
    if (combined.length > overlapSamples) {
      overlapBufferRef.current = combined.slice(-overlapSamples);
    }
    
    // Downsample and convert
    const downsampled = downsampleAudio(combined, audioContextRef.current?.sampleRate || 44100);
    const int16Data = floatToInt16(downsampled);
    
    // Send via WebSocket
    wsRef.current.send(int16Data.buffer);
    
    // Clear current buffers
    audioBufferRef.current = [];
    
    setState(prev => ({ ...prev, bufferSize: combinedLength }));
  }, [downsampleAudio, floatToInt16]);

  // Handle WebSocket messages
  const handleWebSocketMessage = useCallback((event: MessageEvent) => {
    const data = JSON.parse(event.data);
    
    if (data.type === 'transcript') {
      const text = data.text;
      const isFinal = data.isFinal;
      
      // Detect question in real-time
      const punctuation = detectQuestion(text);
      
      setState(prev => ({
        ...prev,
        interimText: isFinal ? '' : text,
        finalText: isFinal ? prev.finalText + ' ' + text : prev.finalText,
        predictedPunctuation: punctuation,
      }));
      
      onTranscript(text + (isFinal ? punctuation : ''), isFinal);
      
      // If final and has punctuation, commit and reset
      if (isFinal && punctuation) {
        silenceStartRef.current = null;
      }
    }
  }, [detectQuestion, onTranscript]);

  // Connect WebSocket
  const connectWebSocket = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) return;
    
    try {
      wsRef.current = new WebSocket(wsUrl);
      
      wsRef.current.onopen = () => {
        setState(prev => ({ ...prev, isConnected: true }));
        reconnectAttemptsRef.current = 0;
        
        // Send initial config
        wsRef.current?.send(JSON.stringify({
          type: 'config',
          sampleRate: SAMPLE_RATE,
          language: 'en',
          model: 'faster-whisper-tiny' // or 'whisper-turbo'
        }));
      };
      
      wsRef.current.onmessage = handleWebSocketMessage;
      
      wsRef.current.onclose = () => {
        setState(prev => ({ ...prev, isConnected: false }));
        
        // Attempt reconnection
        if (reconnectAttemptsRef.current < maxReconnectAttempts) {
          reconnectAttemptsRef.current++;
          setTimeout(connectWebSocket, 1000 * reconnectAttemptsRef.current);
        }
      };
      
      wsRef.current.onerror = (error) => {
        console.error('WebSocket error:', error);
      };
    } catch (error) {
      console.error('Failed to connect WebSocket:', error);
    }
  }, [wsUrl, handleWebSocketMessage]);

  // Process audio chunk
  const processAudioChunk = useCallback((event: AudioProcessingEvent) => {
    const inputBuffer = event.inputBuffer;
    const inputData = inputBuffer.getChannelData(0);
    
    // Calculate audio level for visualization
    const energy = calculateEnergy(inputData);
    const audioLevel = Math.min(energy * 10, 1); // Normalize to 0-1
    
    // VAD detection
    const isVADActive = isSpeechDetected(energy);
    
    setState(prev => ({ ...prev, audioLevel, isVADActive }));
    
    if (isVADActive) {
      // Reset silence timer
      silenceStartRef.current = null;
      
      // Add to buffer
      audioBufferRef.current.push(new Float32Array(inputData));
    } else {
      // Track silence duration
      if (silenceStartRef.current === null) {
        silenceStartRef.current = Date.now();
      } else {
        const silenceDuration = Date.now() - silenceStartRef.current;
        
        // Commit after silence timeout
        if (silenceDuration > VAD_SILENCE_TIMEOUT) {
          // Force send remaining buffer
          sendAudioBuffer();
          silenceStartRef.current = null;
        }
      }
    }
  }, [calculateEnergy, isSpeechDetected, sendAudioBuffer]);

  // Start recording
  const startRecording = useCallback(async () => {
    try {
      // Connect WebSocket first
      connectWebSocket();
      
      // Get microphone access
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: {
          sampleRate: SAMPLE_RATE,
          channelCount: 1,
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
        }
      });
      
      mediaStreamRef.current = stream;
      
      // Create audio context
      const audioContext = new AudioContext({
        sampleRate: SAMPLE_RATE,
      });
      audioContextRef.current = audioContext;
      
      // Create source
      const source = audioContext.createMediaStreamSource(stream);
      sourceNodeRef.current = source;
      
      // Create analyser for visualization
      const analyser = audioContext.createAnalyser();
      analyser.fftSize = 256;
      analyserRef.current = analyser;
      
      // Create processor for VAD and buffering
      const processor = audioContext.createScriptProcessor(BUFFER_SIZE, 1, 1);
      processor.onaudioprocess = processAudioChunk;
      processorNodeRef.current = processor;
      
      // Connect nodes
      source.connect(analyser);
      analyser.connect(processor);
      processor.connect(audioContext.destination);
      
      // Start streaming interval
      streamingIntervalRef.current = setInterval(sendAudioBuffer, STREAMING_INTERVAL);
      
      setState(prev => ({
        ...prev,
        isRecording: true,
        interimText: '',
        finalText: '',
        bufferSize: 0,
      }));
      
    } catch (error) {
      console.error('Failed to start recording:', error);
      alert('Could not access microphone. Please check permissions.');
    }
  }, [connectWebSocket, processAudioChunk, sendAudioBuffer]);

  // Stop recording
  const stopRecording = useCallback(() => {
    // Send any remaining audio
    sendAudioBuffer();
    
    // Clear streaming interval
    if (streamingIntervalRef.current) {
      clearInterval(streamingIntervalRef.current);
      streamingIntervalRef.current = null;
    }
    
    // Disconnect WebSocket
    if (wsRef.current) {
      wsRef.current.close();
      wsRef.current = null;
    }
    
    // Stop audio processing
    if (processorNodeRef.current) {
      processorNodeRef.current.disconnect();
      processorNodeRef.current.onaudioprocess = null;
      processorNodeRef.current = null;
    }
    
    if (sourceNodeRef.current) {
      sourceNodeRef.current.disconnect();
      sourceNodeRef.current = null;
    }
    
    if (analyserRef.current) {
      analyserRef.current.disconnect();
      analyserRef.current = null;
    }
    
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    
    // Clear buffers
    audioBufferRef.current = [];
    overlapBufferRef.current = null;
    vadBufferRef.current = [];
    silenceStartRef.current = null;
    
    setState(prev => ({
      ...prev,
      isRecording: false,
      isVADActive: false,
      audioLevel: 0,
      interimText: '',
      predictedPunctuation: '',
      isConnected: false,
    }));
  }, [sendAudioBuffer]);

  // Toggle recording
  const toggleRecording = useCallback(async () => {
    if (state.isRecording) {
      stopRecording();
    } else {
      await startRecording();
    }
  }, [state.isRecording, startRecording, stopRecording]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      stopRecording();
    };
  }, [stopRecording]);

  return {
    ...state,
    startRecording,
    stopRecording,
    toggleRecording,
  };
}

export default useStreamingTranscription;
